import React, { useState } from "react";
import "../styles/App.css";

const API_BASE = "http://localhost:8000";
const initialForm = { distance: "", relative_velocity: "" };
const STATUS_THEME = {
  SAFE: { border: "#2e7d32", text: "#1b5e20", bg: "#edf7ed" },
  CAUTION: { border: "#ed6c02", text: "#8a4b00", bg: "#fff4e5" },
  RISK: { border: "#d32f2f", text: "#8a1c1c", bg: "#fdecea" },
  "HIGH RISK": { border: "#b71c1c", text: "#7f0000", bg: "#ffebee" },
  COLLIDED: { border: "#4a148c", text: "#4a148c", bg: "#f3e5f5" },
};

function PredictView({
  form,
  loading,
  error,
  result,
  submittedData,
  onChange,
  onSubmit,
  onReset,
}) {
  const theme = result ? (STATUS_THEME[result.predicted_status] || STATUS_THEME.SAFE) : null;

  return (
    <section className="panel mainPanel">
      <div className="panelContent">
        <div className="panelColumn">
          <h2>Input</h2>
          <form onSubmit={onSubmit}>
            <div className="field">
              <label>Distance to Object (m)</label>
              <input
                type="number"
                name="distance"
                value={form.distance}
                onChange={onChange}
                placeholder="e.g. 15"
              />
            </div>

            <div className="field">
              <label>Relative Velocity (m/s)</label>
              <input
                type="number"
                name="relative_velocity"
                value={form.relative_velocity}
                onChange={onChange}
                placeholder="e.g. 10"
              />
            </div>

            {error && <div className="error">{error}</div>}

            <div className="buttonRow">
              <button type="submit" disabled={loading} className="button">
                {loading ? "Predicting..." : "Predict"}
              </button>
              <button type="button" onClick={onReset} className="resetButton">
                Reset
              </button>
            </div>
          </form>
        </div>

        <div className="panelColumn panelOutput">
          <h2>Output</h2>

          {!result && !loading && (
            <div className="placeholder">
              <p>Enter distance and relative velocity to generate a prediction.</p>
            </div>
          )}

          {loading && <div className="placeholder">Predicting...</div>}

          {result && theme && (
            <div
              className="statusBanner"
              style={{ background: theme.bg, border: `2px solid ${theme.border}` }}
            >
              <div>
                <div className="statusLabel" style={{ color: theme.text }}>
                  {result.predicted_status}
                </div>
                <div className="metricRow">
                  <span>Time To </span>
                  <strong>{result.ttc === null ? "N/A" : `${result.ttc.toFixed(2)} s`}</strong>
                </div>
                <div className="messageText">{result.message}</div>
              </div>
            </div>
          )}

          {submittedData && (
            <div className="submittedData">
              <strong>Last Input</strong>
              <div>Distance: {submittedData.distance} m</div>
              <div>Relative Velocity: {submittedData.relative_velocity} m/s</div>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

function HistoryView({ history, histLoading }) {
  return (
    <section className="panel mainPanel">
      <div className="historyViewHeader">
        <h2>Prediction History</h2>
        <p>Recent ADAS-style predictions from the backend.</p>
      </div>

      <div className="historyCard">
        {histLoading ? <p>Loading...</p> : history.length === 0 ? <p>No predictions yet.</p> : (
          <table className="historyTable">
            <thead>
              <tr>
                <th>#</th>
                <th>Distance</th>
                <th>TTC</th>
                <th>Rel. Velocity</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {history.map((row) => (
                <tr key={row.id}>
                  <td>{row.id}</td>
                  <td>{row.distance.toFixed(1)} m</td>
                  <td>{row.ttc === null ? "N/A" : `${row.ttc.toFixed(2)} s`}</td>
                  <td>{row.relative_velocity.toFixed(1)} m/s</td>
                  <td>{row.predicted_status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </section>
  );
}

function App() {
  const [form, setForm] = useState(initialForm);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [submittedData, setSubmittedData] = useState(null);
  const [history, setHistory] = useState([]);
  const [activeView, setActiveView] = useState("predict");
  const [histLoading, setHistLoading] = useState(false);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError(null);
  };

  const resetForm = () => {
    setForm(initialForm);
    setResult(null);
    setError(null);
    setSubmittedData(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setResult(null);

    if (form.distance === "" || form.relative_velocity === "") {
      setError("Distance and relative velocity are required.");
      setLoading(false);
      return;
    }

    const payload = {
      distance: parseFloat(form.distance),
      relative_velocity: parseFloat(form.relative_velocity),
    };

    try {
      const response = await fetch(`${API_BASE}/predict`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        throw new Error("Prediction failed.");
      }

      const data = await response.json();
      setResult(data);
      setSubmittedData(payload);
      setForm(initialForm);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchHistory = async () => {
    setHistLoading(true);
    try {
      const res = await fetch(`${API_BASE}/history?limit=20`);
      setHistory(await res.json());
    } catch {
      setHistory([]);
    } finally {
      setHistLoading(false);
    }
  };

  const switchView = (view) => {
    setActiveView(view);
    if (view === "history") {
      fetchHistory();
    }
  };

  return (
    <div className="page">
      <header className="header">
        <h1>Vehicle Safety Prediction</h1>
        <p>ADAS-style risk estimation from distance and relative velocity</p>
      </header>

      <main className="dashboardSingle">
        <div className="viewSwitch">
          <button
            type="button"
            className={`viewTab ${activeView === "predict" ? "activeTab" : ""}`}
            onClick={() => switchView("predict")}
          >
            Predict
          </button>
          <button
            type="button"
            className={`viewTab ${activeView === "history" ? "activeTab" : ""}`}
            onClick={() => switchView("history")}
          >
            History
          </button>
        </div>

        {activeView === "predict" ? (
          <PredictView
            form={form}
            loading={loading}
            error={error}
            result={result}
            submittedData={submittedData}
            onChange={handleChange}
            onSubmit={handleSubmit}
            onReset={resetForm}
          />
        ) : (
          <HistoryView history={history} histLoading={histLoading} />
        )}
      </main>

      <footer className="footer">
        Vehicle Safety Prediction System · FastAPI + React
      </footer>
    </div>
  );
}

export default App;
